import React, { useCallback, useMemo, useRef, useState } from "react"
import { NavigationProp, useFocusEffect, useNavigation } from "@react-navigation/native";
import { PropsRootStack } from "../../routes/Models";
import { format, parseISO } from "date-fns";
import { PropsModalizeRef } from "@semparar/design-system-app/src/@types/modelize";
import { eventSelectContent, eventScreenViewV3, eventModalView } from '~/constants/functions';
import { getPointsExtract } from '../../services/services';
import { useShallow } from "zustand/react/shallow";
import { useRootStore } from '../../store';
import { AppliedFilters, PERIOD_DAYS_MAP, PointsExtractStatus, PointsTransaction } from "../../services/models";
import { Dimensions } from "react-native";
import { FilterGroup } from "../Extract/Models";
import { getFilteredTransactions } from "../Extract/utils";
import MyOrdersRewardProgramView from "./view";


const MyOrdersRewardProgram = () => {

    const [isRefreshing, setIsRefreshing] = useState(false);

    const modalizeRefFilters = useRef<PropsModalizeRef>(null);
    const emptyImage = "https://image.mkt-semparar.com.br/lib/fe2f117170640475721171/m/1/shopping_cart.png"

    const SKELETON_COUNT = 3;
    const { width } = Dimensions.get('window');

    const { pointsExtract, pointsExtractFilters, pointsExtractActions } =
        useRootStore(
            useShallow((state) => ({
                pointsExtract: state.pointsExtract,
                pointsExtractFilters: state.pointsExtractFilters,
                pointsExtractActions: state.pointsExtractActions
            })),
        );

    const appliedTransactionsFilters = pointsExtractFilters.appliedTransactionsFilters;

    const getFormatDate = (iso?: string) => {
        if (!iso) return '';
        const date = parseISO(iso);
        return format(date, 'dd/MM/yyyy');
    };

    const periodFilters = [
        { label: '7 dias', value: 0 },
        { label: '15 dias', value: 1 },
        { label: '30 dias', value: 2 },
        { label: '60 dias', value: 3 },
        { label: '90 dias', value: 4 },
    ]


    const typeFilters = [
        { label: 'Mais recentes', value: 'ASC' },
        { label: 'Mais antigas', value: 'DESC' },
    ]

    const getFilterGroups: FilterGroup[] = useMemo(() => {
        return [{
            label: 'Períodos',
            options: periodFilters,
        }, {
            label: 'Relevância',
            options: typeFilters,
        }];
    }, []);

    const clearTransactionsFilters = useCallback(() => {
        pointsExtractActions.clearTransactionsFilters();
    }, [pointsExtractActions]);

    const setTransactionsFilters = useCallback(
        (filters: AppliedFilters) => {
            pointsExtractActions.setTransactionsFilters(filters);
        },
        [pointsExtractActions],
    );

    const handleApplyFilters = useCallback(
        (filters: Record<number, unknown>) => {
            const period = filters[0] as number | undefined;
            const types = filters[1] as string | undefined;

            const hasPeriod = period !== undefined && period !== null;
            const hasOrdering = types !== undefined && types !== null;

            const parts: string[] = ['filtrar'];

            if (hasPeriod) {
                const periodDay = periodFilters[period].label.split(' ')[0];
                parts.push(`${periodDay}_dias`);
            }

            if (hasOrdering) {
                const label = typeFilters.find(
                    item => item.value === types
                )?.label;

                if (label) {
                    parts.push(label.toLowerCase());
                }
            }

            const trackingLabel = parts.join('_');

            eventSelectContent({
                content_type: 'cta',
                content_id: `${trackingLabel}`,
                location_1: 'monetizacao',
                location_2: 'hub_recompensas_spmais',
                location_3: 'filtro_meus_pedidos',
            });

            if (!hasPeriod && !hasOrdering) {
                clearTransactionsFilters();
            } else {
                setTransactionsFilters({
                    period: hasPeriod ? period : undefined,
                    order: hasOrdering ? [types] : undefined,
                });
            }
        },
        [setTransactionsFilters, clearTransactionsFilters],
    );

    const handleOpenFilters = () => {
        eventSelectContent({
            content_type: 'cta',
            content_id: 'filtro_pedidos',
            location_1: 'monetizacao',
            location_2: 'hub_recompensas_spmais',
            location_3: 'meus_pedidos',
        });

        modalizeRefFilters.current?.open?.();

        eventModalView({
            content_id: 'filtro_meus_pedidos',
            location_1: 'monetizacao',
            location_2: 'hub_recompensas_spmais',
            location_3: 'meus_pedidos',
        });
    }

    const handleDetailsOrders = () => {
        eventSelectContent({
            content_type: 'cta',
            content_id: 'detalhe_pedido',
            location_1: 'monetizacao',
            location_2: 'hub_recompensas_spmais',
            location_3: 'meus_pedidos',
        });
    }

    const getTransactionsWithFilters = useCallback(
        (transactions: PointsTransaction[]): PointsTransaction[] => {
            let filtered = transactions;
            if (appliedTransactionsFilters) {
                const filtersWithDays: AppliedFilters = {
                    ...appliedTransactionsFilters,
                    period: appliedTransactionsFilters.period !== undefined
                        ? PERIOD_DAYS_MAP[appliedTransactionsFilters.period]
                        : undefined,
                };
                filtered = getFilteredTransactions(filtered, filtersWithDays);
            }

            return filtered;
        },
        [appliedTransactionsFilters],
    );

    const getActiveFiltersCount = () => {
        let count = 0;
        if (appliedTransactionsFilters?.period !== undefined && appliedTransactionsFilters?.period !== null) count++;
        if (appliedTransactionsFilters?.order?.length) count++;
        return count > 0 ? count.toString() : undefined;
    }

    const getInitialFilters = useMemo(() => {
        const filters: Record<number, unknown> = {};
        if (appliedTransactionsFilters?.period !== undefined && appliedTransactionsFilters?.period !== null) {
            filters[0] = appliedTransactionsFilters.period;
        }
        if (appliedTransactionsFilters?.order?.length) {
            filters[1] = appliedTransactionsFilters.order[0];
        }
        return filters;
    }, [appliedTransactionsFilters]);

    const getOrdersTransactions = () => {
        if (!pointsExtract.extractData) return [];

        const transactions = getTransactionsWithFilters(
            pointsExtract.extractData.transactions,
        );

        return transactions
    }
    const ordersTransactionsData = getOrdersTransactions()

    const isLoading = pointsExtract.status === PointsExtractStatus.LOADING
    const isError = pointsExtract.status === PointsExtractStatus.ERROR

    const navigation = useNavigation<NavigationProp<PropsRootStack>>();

    const handleGoBack = () => {
        clearTransactionsFilters()
        pointsExtractActions.reset()
        navigation.goBack()
    }

    const handleRefresh = async () => {
        setIsRefreshing(true);
        await getPointsExtract({ type: 'Resgate' });
        setIsRefreshing(false);
    };

    const hasFocused = useRef(false);
    useFocusEffect(
        React.useCallback(() => {
            if (!hasFocused.current) {
                eventScreenViewV3(
                    'meus_pedidos',
                    'hub_recompensas_spmais',
                    'monetizacao',
                    {
                        location_1: 'monetizacao',
                        location_2: 'hub_recompensas_spmais',
                        location_3: 'meus_pedidos',
                    }
                );
                pointsExtractActions.reset()
                getPointsExtract({ type: 'Resgate' });
                hasFocused.current = true;
            }
            return () => {
                hasFocused.current = false;
            };
        }, [])
    )

    return (
        <MyOrdersRewardProgramView
            myOrders={ordersTransactionsData}
            emptyImage={emptyImage}
            isLoading={isLoading}
            isError={isError}
            filterGroups={getFilterGroups}
            modalizeRefFilters={modalizeRefFilters}
            formatDate={getFormatDate}
            handleGoBack={handleGoBack}
            handleOpenFilters={handleOpenFilters}
            handleDetailsOrders={handleDetailsOrders}
            isRefreshing={isRefreshing}
            handleRefresh={handleRefresh}
            skeletonCount={SKELETON_COUNT}
            screenWidth={width}
            handleApplyFilters={handleApplyFilters}
            initialFilters={getInitialFilters}
            activeFiltersCount={getActiveFiltersCount()}

        />
    )

}

export default MyOrdersRewardProgram;

